function Home() {
  return (
    <div
      className="w-full h-[100vh]"
      style={{
        height: 100,
        width: 100,
        backgroundImage: "url('public/fondo6.jpg')", // Ruta relativa desde public
        backgroundSize: 'cover', // Esto hace que la imagen cubra todo el div
        backgroundPosition: 'center', // Centra la imagen
      }}
    >
      Insertar imagen
    </div>
  );
}

export default Home;
